INSERT INTO transfer_outgoing VALUES(1,'2026-summer',3,'Arsenal','MEDIUM-LOW','아르테타 주도 관심 지속되나 빌라 "매각 의사 없음" 재확인 — 공식 오퍼 없음, 에메리는 콘사를 핵심 자원으로 규정하고 오퍼 자체를 검토하지 않겠다는 입장.','https://readastonvilla.com/2026/07/03/arsenal-konsa-interest-aston-villa-60m-transfer-stance/ , https://thehardtackle.com/transfer-news/2026/07/07/aston-villa-reluctant-to-sell-ezri-konsa-amid-arsenal-links/','3티어 다수(하드태클/리드아스톤빌라)만 보도, 텔레그래프 등 상위 매체 팔로업 없음 — 등급 하향(MEDIUM→MEDIUM-LOW). 2026-07-08 확인.');
INSERT INTO transfer_outgoing VALUES(2,'2026-summer',13,'Arsenal','MEDIUM-HIGH','£130m(요구)/£80m(청취 가능) 밸류. 로마노: 아스날 측 "매우 좋은 진전"(very good progress) — 단, 빌라는 영국 신기록급 이적료 아니면 매각 거부 입장 유지. 2031년 계약이라 매각 압박 없음.','https://www.skysports.com/football/transfer-paper-talk (Sky Sports), https://www.teamtalk.com/arsenal/morgan-rogers-transfer-news-record-bid-imminent-from-arsenal-villa (로마노 인용)','1티어(로마노) "매우 좋은 진전" 보도로 근거 보강 — 등급은 MEDIUM-HIGH 유지(합의/advanced talks 단계 아님). 2026-07-08 확인.');
INSERT INTO transfer_outgoing VALUES(3,'2026-summer',1,'Juventus','HIGH','Fabrizio Romano(1티어, via CaughtOffside) — 유벤투스가 마르티네스 측에 직접 접촉(2026-07-08). Goal.com/JuveFC — 개인조건(3년, 2029년까지, 연봉 €5.5m 네트로 삭감 수용) 구두 합의. 이적료 갭만 남음: 빌라 요구 €10-15m vs 유벤투스 제시 €5m, 월드컵 후 협상 예정. 대안: 비카리오(토트넘).','https://www.caughtoffside.com/2026/07/08/juventus-direct-contact-emiliano-martinez-fabrizio-romano/ ; https://www.goal.com/en/lists/emi-martinez-verbally-agrees-juventus-transfer-aston-villa-and-argentina-goalkeeper-prepared-to-reduce-salary/blt15e7adefed63d273 ; https://www.juvefc.com/juventus-personal-terms-emi-martinez-aston-villa/','HIGH — 1티어(Romano) 직접접촉 확인 + 개인조건 구두합의 다중보도. 이적료 협상만 미해결.');
INSERT INTO transfer_outgoing VALUES(4,'2026-summer',9,'Fenerbahçe / Al-Ittihad','MEDIUM','Football Insider(2티어) — PSR(재정건전성) 부담으로 빌라가 "거대한 오퍼"에는 매각 수용 가능성. 페네르바흐체·알 이티하드 관심 거론되나 구체적 협상 단계는 아님. 틸레만스 본인은 사우디 이적 의향 없음으로 보도(3티어). 에메리는 그를 잔류시키고 싶어함 — 매각보다는 다른 선수 매각으로 자금 마련 선호.','https://www.footballinsider247.com/youri-tielemans-aston-villa-could-now-accept-huge-offer-amid-financial-concern ; https://www.sportsmole.co.uk/football/aston-villa/transfer-talk/news/emerys-psr-puzzle-who-could-villa-sell-to-keep-influential-tielemans_597744.html','MEDIUM — 2티어(Football Insider) 1곳, PSR 매각 가능성 보도. 구체적 클럽 협상 단계 아님.');
